from flask import Flask, send_from_directory

app = Flask(__name__)

@app.route('/static/<path:filename>')
def legacy_static(filename):
    # Check if the file exists in the 'uploads' directory
    try:
        return send_from_directory('uploads', filename)
    except FileNotFoundError:
        # Fallback to old naming convention (if applicable, modify as per your naming pattern)
        old_filename = "old_" + filename  # Example transformation
        return send_from_directory('uploads', old_filename)

if __name__ == '__main__':
    app.run(debug=True)